/* Saint of the Day - Daily Content Database */

const DAILY_CONTENT = {
"01-01": {
  title: "January 1  Mary, Mother of God",
  story: "Today is the feast of Mary, Mother of God—celebrated on January 1, the octave day of Christmas. Mary is honored with this title because her Son, Jesus, is truly God and truly man. Mary lived in Nazareth, and Christian tradition names her holy parents as Saints Joachim and Anne. Tradition also connects Mary’s early life with Jerusalem. But the most important true fact is this: Mary said a brave and loving YES to God, and she cared for Jesus with a mother’s tender love.\n\nOn the night Jesus was born in Bethlehem, shepherds came in a hurry. They told Mary and Joseph about angels and a song of peace. Mary did not interrupt or boast. She listened quietly, like someone holding a treasure. She kept those words safe inside her heart and thought about them again and again.\n\nThat is one reason children will love Mary: she is gentle, strong, and close to Jesus. And that is why the Church begins the new year with her—so every family can start again with peace. When you feel confused, Mary teaches you to pray. When you feel afraid, Mary teaches you to trust. And when you want to come closer to Jesus, Mary always points you to Him.",
  bibleVerse: "Luke 2:19\nBut Mary kept all these words, pondering them in her heart.",
  meaning: "This verse teaches us that Mary listened carefully and trusted God, even when she did not understand everything. Children can learn from Mary to keep good thoughts in their hearts and trust God quietly.",
  prayer: "Dear Mother Mary, Mother of God, thank you for saying yes to God and bringing Jesus to the world. Please pray for me and my family today. Help me trust God, love Jesus, and keep good thoughts in my heart. Amen.",
  action: "Do one quiet act of love today: say a Hail Mary and help your mother (or the person who cares for you) with one small thing without being asked."
},
"01-02": {
  title: "January 2  Saints Basil the Great and Gregory of Nazianzus",
  story: "Saint Basil and Saint Gregory were born in the land of Cappadocia, in what is now part of Turkey. Basil was born into a large Christian family—his parents, Basil the Elder and Emmelia, taught their children to love God deeply. Several members of Basil’s family became saints, including his sister Saint Macrina. Gregory was born to faithful parents named Gregory and Nonna, who prayed and guided him with love.\n\nAs young men, Basil and Gregory became very close friends while studying together. They encouraged each other to pray, to learn, and to live holy lives. Basil later became a bishop and cared for the poor, the sick, and the hungry. He even helped create places where people could receive food and medical care. Gregory also became a bishop and used his gentle words to explain the truth about God when the Church was facing confusion.\n\nThe Church celebrates Saints Basil and Gregory on January 2 because of their great love for God, their friendship, and their courage in teaching the truth. Their lives show children that learning, kindness, and friendship can all be paths to holiness when they are offered to God.",
  bibleVerse: "Proverbs 27:17\nIron sharpeneth iron, so a man sharpeneth the countenance of his friend.",
  meaning: "This verse means that good friends help each other become better. When friends pray together and choose what is right, they help each other grow closer to God.",
  prayer: "Dear God, thank You for Saints Basil and Gregory and for the gift of good friends. Help me learn what is right, be kind to others, and choose friends who help me love You more. Amen.",
  action: "Do one kind thing today for a friend or sibling, encouraging them just as Saints Basil and Gregory encouraged each other."
},
"01-03": {
  title: "January 3  Saint Genevieve of Paris",
  story: "Saint Genevieve was born in the village of Nanterre, near Paris in France. Her parents were named Severus and Gerontia, and they raised her to love God and to pray from a young age. When Genevieve was still a child, a holy bishop named Saint Germanus visited her village and blessed her, telling her that God had a special plan for her life. From that day on, Genevieve chose to belong completely to God.\n\nAs she grew older, Genevieve lived a simple life of prayer and kindness. She cared deeply for poor people and often gave food to those who were hungry. When enemies threatened the city of Paris, many people were afraid and wanted to run away. Genevieve courageously asked them to trust God instead. She prayed day and night, and the city was saved from harm. Because of her faith and bravery, the people of Paris loved her and remembered her as a protector.\n\nThe Church celebrates Saint Genevieve on January 3. She is honored as a saint because she trusted God completely, helped others in times of fear, and showed that prayer can bring peace even in difficult moments.",
  bibleVerse: "Psalm 56:4\nIn God I have put my trust; I will not fear what flesh can do against me.",
  meaning: "This verse reminds children that when we trust God, we do not need to be afraid. God stays with us and protects us even in difficult times.",
  prayer: "Dear God, thank You for Saint Genevieve, who trusted You even when others were afraid. Please help me to be brave, to pray when things are hard, and to care for people who need help. Amen.",
  action: "Say a short prayer today for someone who feels afraid, and do one kind thing to help them feel safe."
},
"01-04": {
  title: "January 4  Saint Elizabeth Ann Seton",
  story: "Saint Elizabeth Ann Seton was born in New York City in the United States. Her parents were Richard and Catherine Bayley. Elizabeth lost her mother when she was very young, which made her learn to trust God even in sadness. As she grew up, Elizabeth married and had children, but later her husband died, leaving her with great responsibility and sorrow.\n\nDuring this difficult time, Elizabeth learned more about the Catholic faith and chose to become Catholic, even though this decision was not easy and many people did not understand her choice. She trusted God and dedicated her life to caring for children and teaching them about Jesus. Elizabeth became the founder of the first Catholic school for children in America and later started a religious community to continue this work.\n\nThe Church celebrates Saint Elizabeth Ann Seton on January 4 because of her faith, courage, and love for children. She became a saint because she trusted God through loss, helped educate young people, and showed that love and faith can grow even during hard times.",
  bibleVerse: "Proverbs 3:5\nTrust in the Lord with all thy heart, and lean not upon thy own prudence.",
  meaning: "This verse teaches us to trust God with our whole heart instead of worrying too much. God knows what is best for us, even when life feels hard.",
  prayer: "Dear God, thank You for Saint Elizabeth Ann Seton, who trusted You even when life was hard. Please help me trust You every day, learn with joy, and show kindness to others. Amen.",
  action: "Thank a teacher or parent today and try your best in one lesson or task, offering your work to God."
},
"01-05": {
  title: "January 5  Saint John Neumann",
  story: "Saint John Neumann was born in a small village called Prachatice, in what is now the Czech Republic. His parents were named Philip and Agnes Neumann, and they raised him to love learning and prayer. From a young age, John wanted to become a priest and help people grow closer to God.\n\nAs an adult, John traveled far to the United States to serve as a priest. He walked long distances to visit families, taught children their prayers, and cared especially for poor and immigrant families. Later, he became a bishop and worked hard to build Catholic schools so children could learn about Jesus. The Church celebrates Saint John Neumann on January 5 because of his love for children, his dedication to education, and his faithful service to God.",
  bibleVerse: "Matthew 19:14\nSuffer the little children, and forbid them not to come to me: for the kingdom of heaven is for such.",
  meaning: "Jesus loves children very much and wants them to come close to Him. This verse teaches us that children are important to God and welcome in His family.",
  prayer: "Dear God, thank You for Saint John Neumann, who loved children and helped them learn about You. Please help me love learning, be kind to others, and serve You with a joyful heart. Amen.",
  action: "Say one prayer today for your teachers and try your best in one lesson or task as a gift to God."
},
"01-06": {
  title: "January 6  The Epiphany of the Lord",
  story: "On January 6, the Church celebrates the Epiphany of the Lord. This feast remembers the day when the Wise Men, also called the Magi, came from faraway lands to visit baby Jesus. The Magi were not kings, but learned men who studied the stars. When they saw a bright new star in the sky, they understood that a great King had been born.\n\nThe Wise Men traveled a long and difficult journey, guided only by the star. When they finally found Jesus in Bethlehem, they bowed down and worshipped Him. They offered Him three gifts: gold to honor Him as King, frankincense to honor Him as God, and myrrh to remind us that Jesus came to save the world through sacrifice.\n\nThe Epiphany teaches us that Jesus came not only for one people, but for everyone in the world. The Church celebrates this feast on January 6 to remind us that Jesus is the Light for all nations and that everyone is invited to know and love Him.",
  bibleVerse: "Matthew 2:11\nAnd entering into the house, they found the child with Mary his mother, and falling down they adored him: and opening their treasures, they offered him gifts; gold, frankincense, and myrrh.",
  meaning: "This verse teaches that Jesus is worthy of love and worship. Like the Wise Men, we can offer Jesus our best gifts—our kindness, our prayers, and our love.",
  prayer: "Dear Jesus, You are the Light of the world. Thank You for coming to save everyone. Help me follow You each day and offer You my love and good actions. Amen.",
  action: "Do one good deed today as a gift for Jesus, and thank Him for loving all people."
},
"01-07": {
  title: "January 7  Saint Raymond of Peñafort",
  story: "Saint Raymond of Peñafort was born in the town of Peñafort, in Spain. His parents were noble and faithful Catholics who taught him to love God and to value honesty and learning. Raymond was very intelligent, and as a young man he studied hard so he could help others understand what was right.\n\nRaymond became a priest and later helped the Church by explaining God’s laws clearly and kindly. Many people came to him when they were confused or troubled, and Raymond patiently helped them choose what was good and fair. Even though he was very learned, he lived simply and humbly. He cared deeply for people who were poor or treated unfairly and wanted everyone to follow God with a clear conscience.\n\nThe Church celebrates Saint Raymond on January 7. He became a saint because he used his wisdom to help others, spoke the truth with kindness, and showed that learning can be a way to serve God when it is guided by love.",
  bibleVerse: "James 1:5\nBut if any of you want wisdom, let him ask of God, who giveth to all men abundantly, and upbraideth not: and it shall be given him.",
  meaning: "This verse teaches that God loves to help us learn what is right. When we ask God for wisdom, He is happy to guide us and help us make good choices.",
  prayer: "Dear God, thank You for Saint Raymond, who used his learning to help others. Please help me ask You for wisdom, choose what is right, and be kind to everyone. Amen.",
  action: "Before making a choice today, pause and ask God quietly to help you choose what is good and kind."
},
"01-08": {
  title: "January 8  Saint Severin of Noricum",
  story: "Saint Severin lived many years ago in a land called Noricum, which is part of Europe today. The Church does not record the names of his parents or the exact place where he was born, but it remembers clearly the kind of life he lived. Severin chose a simple life of prayer and trusted God completely.\n\nDuring a difficult time when people were poor, hungry, and afraid, Saint Severin traveled from place to place helping them. He shared food with the hungry, protected the weak, and encouraged people not to lose hope. He taught them to pray and reminded them that God had not forgotten them. Many people saw that Severin cared more about helping others than about himself.\n\nThe Church celebrates Saint Severin on January 8 because of his great love for the poor, his strong faith, and his kindness during hard times. He became a saint because he trusted God, helped people in need, and showed that love and prayer can bring light even in dark moments.",
  bibleVerse: "Matthew 25:40\nAmen I say to you, as long as you did it to one of these my least brethren, you did it to me.",
  meaning: "This verse teaches that when we help others, we are also showing love to Jesus. Every kind action, even a small one, is important to God.",
  prayer: "Dear God, thank You for Saint Severin, who helped the poor and trusted You in difficult times. Please help me notice people who need help and show them kindness and love. Amen.",
  action: "Share something today—your food, your time, or your kindness—with someone who needs it."
},
"01-09": {
  title: "January 9  Saint Adrian of Canterbury",
  story: "Saint Adrian was born in North Africa and later traveled to Europe to serve the Church. The names of his parents are not recorded, but the Church remembers Adrian as a man who loved learning and prayer. He became a monk and spent his life studying God’s word so he could teach others.\n\nSaint Adrian was invited to England, where he helped lead a famous school in Canterbury. Children and adults came from many places to learn from him. Adrian taught them about the Bible, prayer, languages, and how to live good Christian lives. He was known for being patient, wise, and kind to everyone who wanted to learn.\n\nThe Church celebrates Saint Adrian on January 9. He became a saint because he used his knowledge to serve God, helped others grow in faith, and showed that teaching is a beautiful way to love and serve the Church.",
  bibleVerse: "Proverbs 4:7\nWisdom is the principal thing; therefore get wisdom: and with all thy getting get understanding.",
  meaning: "This verse teaches that learning good and true things is very important. God is happy when we try to understand what is right and grow wiser each day.",
  prayer: "Dear God, thank You for Saint Adrian, who loved learning and helped others grow in faith. Please help me enjoy learning, listen carefully, and use what I learn to do good. Amen.",
  action: "Pay close attention in school or catechism today and thank God for the gift of learning."
},
"01-10": {
  title: "January 10  Saint Gregory of Nyssa",
  story: "Saint Gregory of Nyssa was born in Cappadocia, a land that is part of present-day Turkey. He was born into a holy Christian family. His parents were named Basil the Elder and Emmelia, and they taught their children to love God deeply. Several members of Gregory’s family became saints, including his brother Saint Basil the Great and his sister Saint Macrina.\n\nGregory grew up learning about God at home and at school. As an adult, he became a bishop and helped the Church by teaching people about God’s love and goodness. Gregory explained difficult ideas in gentle ways so that people could understand them better. He reminded everyone that God is full of mercy and that we grow closer to God by loving others.\n\nThe Church celebrates Saint Gregory of Nyssa on January 10. He became a saint because he used his learning to teach about God with kindness, lived a faithful life, and showed that growing in goodness is a lifelong journey.",
  bibleVerse: "Matthew 5:8\nBlessed are the clean of heart: for they shall see God.",
  meaning: "This verse teaches that when our hearts are loving and kind, we can feel close to God. Choosing good thoughts and actions helps us grow closer to Him.",
  prayer: "Dear God, thank You for Saint Gregory of Nyssa and his holy family. Please help me keep my heart clean, be kind to others, and grow closer to You each day. Amen.",
  action: "Try to keep your heart kind today by speaking gently and choosing one good thought or action."
},
"01-11": {
  title: "January 11  Saint Hyginus, Pope and Martyr",
  story: "Saint Hyginus lived many years ago and was born in Athens, a city known for learning. The Church does not record the names of his parents, but it remembers Hyginus as a man who loved truth and faith. He later traveled to Rome and became Pope during a difficult time for the early Church.\n\nAs Pope, Saint Hyginus helped protect the Church from false teachings and guided Christians to remain faithful to Jesus. Many people at that time were afraid because Christians were often treated badly. Hyginus encouraged them to stay strong, pray together, and trust God. He cared deeply for the Church and served bravely, even though it was dangerous.\n\nThe Church celebrates Saint Hyginus on January 11. He became a saint because he courageously led the Church, defended the true faith, and remained faithful to Jesus even when it cost him his life.",
  bibleVerse: "Matthew 10:32\nEvery one therefore that shall confess me before men, I will also confess him before my Father who is in heaven.",
  meaning: "This verse teaches that being faithful to Jesus is very important. God is happy when we choose Him and are not afraid to follow what is right.",
  prayer: "Dear God, thank You for Saint Hyginus, who stayed faithful even when it was hard. Please help me love Jesus, choose what is right, and trust You every day. Amen.",
  action: "Do one brave thing today for Jesus, such as saying a prayer in public or choosing kindness when it is not easy."
},
"01-12": {
  title: "January 12  Saint Marguerite Bourgeoys",
  story: "Saint Marguerite Bourgeoys was born in Troyes, France. Her parents were named Abraham Bourgeoys and Guillemette Garnier, and they raised their children in the Catholic faith. Marguerite loved God from a young age and wanted to serve Him by helping others, especially children.\n\nAs a young woman, Marguerite felt called to teach children about God. She traveled far across the ocean to a new land called Canada. Life there was difficult, with cold weather and few comforts, but Marguerite did not give up. She opened schools so girls could learn, pray, and grow in faith. She believed that learning was a gift from God and that every child deserved education.\n\nThe Church celebrates Saint Marguerite Bourgeoys on January 12. She became a saint because of her courage, her love for children, and her dedication to teaching. Her life shows children that helping others learn and grow is a beautiful way to serve God.",
  bibleVerse: "Proverbs 22:6\nTrain up a child in the way he should go: and when he is old, he will not depart from it.",
  meaning: "This verse teaches that learning good values from a young age helps us grow into kind and faithful adults. God is happy when we learn and follow what is right.",
  prayer: "Dear God, thank You for Saint Marguerite Bourgeoys, who loved teaching children. Please help me enjoy learning, be thankful for my teachers, and use what I learn to do good. Amen.",
  action: "Listen carefully in class today and thank God for one thing you learned."
},
"01-13": {
  title: "January 13  Saint Hilary of Poitiers",
  story: "Saint Hilary was born in the city of Poitiers in France. His parents were not Christians at first, but they raised Hilary to love learning and to search for what is true. As he studied and thought deeply, Hilary came to know Jesus and chose to become a Christian. He later became a bishop because of his strong faith and love for God.\n\nDuring Hilary’s time, many people were confused about who Jesus really is. Saint Hilary bravely taught that Jesus is truly the Son of God. Because he spoke the truth, Hilary was treated badly and even sent far away from his home. Still, he did not become angry or give up. He continued to pray, write, and teach with patience and love.\n\nThe Church celebrates Saint Hilary on January 13. He became a saint because he loved the truth, taught about Jesus with courage, and remained faithful to God even when it was difficult.",
  bibleVerse: "John 8:32\nAnd you shall know the truth, and the truth shall make you free.",
  meaning: "This verse teaches that knowing and loving what is true helps us live good and happy lives. When we choose truth and follow Jesus, our hearts become free.",
  prayer: "Dear God, thank You for Saint Hilary, who loved the truth and taught others about Jesus. Please help me choose what is right, speak the truth kindly, and follow You every day. Amen.",
  action: "Tell the truth today, even in a small thing, and ask God to help you choose what is right."
},
"01-14": {
  title: "January 14  Saint Devasahayam Pillai",
  story: "Saint Devasahayam Pillai was born in the village of Nattalam, in present-day Tamil Nadu, India. He was born into a Hindu family, and his parents named him Neelakanda Pillai. As a young man, he worked in the royal court and lived a comfortable life.\n\nWhile serving the king, Neelakanda met a Christian officer who spoke to him about Jesus. Neelakanda listened carefully and felt his heart change. He learned about the love of Jesus and chose to become a Christian. At his baptism, he received the name Devasahayam, which means “God helps.”\n\nAfter becoming Christian, Devasahayam treated everyone equally and spoke kindly about Jesus. This made some people angry. He was punished, treated badly, and finally killed because he refused to give up his faith. Devasahayam accepted his suffering with patience and forgave those who hurt him. The Church celebrates Saint Devasahayam Pillai on January 14 because he courageously chose Jesus and remained faithful until the end.",
  bibleVerse: "Matthew 5:10\nBlessed are they that suffer persecution for justice’ sake: for theirs is the kingdom of heaven.",
  meaning: "This verse teaches that God is close to people who choose what is right, even when it is hard. Jesus promises great joy to those who stay faithful to Him.",
  prayer: "Dear Jesus, thank You for Saint Devasahayam Pillai, who loved You more than anything else. Please help me be brave in my faith, choose kindness, and trust You every day. Amen.",
  action: "Stand up for what is right today, even in a small way, and say a prayer for people who are treated unfairly."
},
"01-15": {
  title: "January 15  Saint Paul the Hermit",
  story: "Saint Paul the Hermit was born in Egypt many centuries ago. His parents were wealthy Christians who taught him to love God, but they died when Paul was still young. During a time when Christians were treated badly, Paul chose to leave his home and live alone in the desert so he could pray and trust God completely.\n\nPaul lived a very simple life in the desert. He prayed every day, trusted God for food and shelter, and learned to be happy with very little. Tradition tells us that God took care of Paul in wonderful ways and that he lived many years in peace and prayer. Near the end of his life, another holy man named Saint Anthony visited him and learned from Paul’s deep love for God.\n\nThe Church celebrates Saint Paul the Hermit on January 15. He became a saint because he trusted God completely, lived a life of prayer, and showed that being close to God is more important than riches or comfort.",
  bibleVerse: "Matthew 6:33\nBut seek ye first the kingdom of God, and his justice, and all these things shall be added unto you.",
  meaning: "This verse teaches that God should come first in our lives. When we trust God and choose Him above everything else, He takes care of us.",
  prayer: "Dear God, thank You for Saint Paul the Hermit, who trusted You with his whole life. Please help me remember You each day, pray with love, and trust You to take care of me. Amen.",
  action: "Spend a quiet minute today talking to God in prayer and thank Him for caring for you."
},
"01-16": {
  title: "January 16  Saint Marcellus I, Pope and Martyr",
  story: "Saint Marcellus I lived in Rome during the early years of the Church. The names of his parents are not recorded, but the Church remembers him as a faithful priest who later became Pope at a very difficult time. Many Christians were afraid because the Church was being persecuted, and some people had stopped practicing their faith.\n\nAs Pope, Saint Marcellus worked hard to help people return to God. He encouraged prayer, repentance, and forgiveness, reminding everyone that God’s mercy is always available. He helped organize the Church so that Christians could support one another and grow stronger in faith. Because of his courage and leadership, Marcellus made powerful leaders angry. He suffered greatly and died because he remained faithful to Jesus.\n\nThe Church celebrates Saint Marcellus I on January 16. He became a saint because he bravely led the Church, cared for God’s people, and stayed faithful to Jesus even when it cost him his life.",
  bibleVerse: "Galatians 6:9\nAnd in doing good, let us not fail; for in due time we shall reap, not failing.",
  meaning: "This verse teaches that doing good is always worth it, even when it is hard. God sees our efforts and blesses those who stay faithful and kind.",
  prayer: "Dear God, thank You for Saint Marcellus, who stayed strong in faith and helped others return to You. Please help me do good each day, be patient, and trust You always. Amen.",
  action: "Do one good thing today even if it feels difficult, and offer it to God with love."
},
"01-17": {
  title: "January 17  Saint Anthony the Great",
  story: "Saint Anthony the Great was born in Egypt many centuries ago. His parents were faithful Christians who taught him to love God and to pray. When Anthony was still young, his parents died, and he was left to care for his sister. One day, Anthony heard Jesus’ words in the church and understood that God was calling him to give his life completely to Him.\n\nAnthony chose a simple life and went to live in the desert so he could pray and listen to God without distractions. Many people came to him for advice because they saw his kindness, wisdom, and strong faith. Even though he lived simply, Anthony helped many people grow closer to God through his words and example.\n\nThe Church celebrates Saint Anthony the Great on January 17. He became a saint because he trusted God fully, lived a life of prayer, and showed that choosing God above everything else brings true joy and peace.",
  bibleVerse: "Matthew 19:21\nJesus saith to him: If thou wilt be perfect, go sell what thou hast, and give to the poor, and thou shalt have treasure in heaven: and come, follow me.",
  meaning: "This verse teaches that following Jesus sometimes means letting go of things we do not need. When we choose God first, our hearts become rich with love and joy.",
  prayer: "Dear God, thank You for Saint Anthony the Great, who trusted You with his whole life. Please help me love You, pray with a sincere heart, and choose what matters most. Amen.",
  action: "Give up one small thing today (like extra screen time or a treat) and offer it to God with love."
},
"01-18": {
  title: "January 18  Saint Margaret of Hungary",
  story: "Saint Margaret of Hungary was born in Hungary to King Béla IV and Queen Maria Laskarina. Her parents promised God that they would dedicate their child to Him if their country was saved from great danger. When Margaret was still very young, her parents kept their promise and offered her life to God.\n\nMargaret grew up in a convent, where she learned to pray, help others, and live simply. Even though she was a princess, she chose a humble life and served everyone with kindness. She helped the sick, comforted the poor, and spent much time praying for peace in her country. Margaret was known for her gentle heart and joyful obedience.\n\nThe Church celebrates Saint Margaret of Hungary on January 18. She became a saint because she freely chose God, lived humbly, and showed that loving service and prayer can bring peace to many people.",
  bibleVerse: "Psalm 100:2\nServe ye the Lord with gladness.",
  meaning: "This verse teaches that serving God should be done with joy. When we help others happily, we are also serving God.",
  prayer: "Dear God, thank You for Saint Margaret of Hungary, who served You with joy and love. Please help me obey gladly, help others, and love You every day. Amen.",
  action: "Do one helpful task today with a happy heart and offer it to God."
},
"01-19": {
  title: "January 19  Saint Henry of Uppsala",
  story: "Saint Henry was born in England and later became a priest and bishop because of his deep love for God. He felt called to travel far from his home to share the Christian faith with others. Henry went to the land of Finland, where many people had not yet heard about Jesus.\n\nLife was difficult in that land, but Saint Henry patiently taught, prayed, and helped the people learn about God’s love. He cared for the poor, encouraged peace, and guided others with kindness. Some people became angry because Henry spoke about Jesus and tried to lead them toward what was right. Even then, Henry did not respond with anger. He remained faithful and brave until the end of his life.\n\nThe Church celebrates Saint Henry of Uppsala on January 19. He became a saint because he shared the faith with courage, loved the people he served, and stayed faithful to Jesus even when it was dangerous.",
  bibleVerse: "Matthew 28:19\nGoing therefore, teach ye all nations; baptizing them in the name of the Father, and of the Son, and of the Holy Ghost.",
  meaning: "This verse teaches that Jesus wants His love to be shared with everyone. We can share our faith by being kind, loving, and helpful to others.",
  prayer: "Dear Jesus, thank You for Saint Henry of Uppsala, who shared Your love with courage. Please help me be kind, speak gently about You, and follow You every day. Amen.",
  action: "Show God’s love today by being kind to someone new or by saying a short prayer for people in other countries."
},
"01-20": {
  title: "January 20  Saint Sebastian",
  story: "Saint Sebastian lived in Rome during a time when it was dangerous to be a Christian. He became a soldier in the Roman army, but his heart belonged to Jesus. Sebastian quietly helped Christians who were in prison and encouraged them to stay strong in their faith.\n\nWhen the emperor discovered that Sebastian was a Christian, he ordered that Sebastian be punished. Roman soldiers tied him and shot him with arrows. Sebastian did not die, and Christians cared for him until he recovered. Later, Sebastian bravely returned to speak the truth about Jesus and to defend Christians who were suffering. Because he refused to give up his faith, the emperor ordered that Sebastian be beaten with clubs, and he gave his life for Jesus.\n\nThe Church celebrates Saint Sebastian on January 20. He became a saint because he courageously followed Jesus, helped others stay faithful, and chose love and faith even when it cost him his life.",
  bibleVerse: "Psalm 27:1\nThe Lord is my light and my salvation, whom shall I fear?",
  meaning: "This verse teaches that God gives us courage when we feel afraid. When God is with us, we do not need to fear anything.",
  prayer: "Dear God, thank You for Saint Sebastian, who trusted You and stayed faithful to Jesus. Please help me be brave, choose what is right, and trust You when I feel afraid. Amen.",
  action: "When you feel scared today, say a short prayer and remember that God is always with you."
},
"01-21": {
  title: "January 21  Saint Agnes of Rome",
  story: "Saint Agnes lived in Rome and loved Jesus from a very young age. She decided to belong completely to God and promised to love Him above everything else. Many people admired her courage and faith, even though she was still very young.\n\nWhen Agnes refused to give up her faith in Jesus, she was punished because she would not stop believing in Him. Saint Agnes remained calm and prayerful, trusting God with her whole heart. According to Church tradition, Agnes was killed with a sword because she chose to stay faithful to Jesus.\n\nThe Church celebrates Saint Agnes on January 21. She became a saint because she loved Jesus more than anything else and bravely gave her life rather than deny her faith.",
  bibleVerse: "Matthew 5:8\nBlessed are the clean of heart: for they shall see God.",
  meaning: "This verse teaches that having a pure and loving heart helps us stay close to God. When we choose goodness and honesty, God is happy with us.",
  prayer: "Dear God, thank You for Saint Agnes, who loved You with her whole heart. Please help me choose what is right, stay close to You, and be brave in my faith. Amen.",
  action: "Choose one good thought or action today and offer it to God with love."
},
"01-22": {
  title: "January 22  Saint Vincent of Saragossa",
  story: "Saint Vincent lived in Spain and served the Church as a deacon. He helped his bishop by preaching, caring for the poor, and encouraging Christians to stay faithful to Jesus. Vincent loved God deeply and spoke bravely about his faith.\n\nWhen Christians were being persecuted, Vincent was arrested because he refused to give up his faith. According to Church tradition, Vincent was hurt with iron hooks and placed on a hot gridiron. Through everything, Vincent remained peaceful and trusted God completely. He never stopped loving Jesus and encouraging others to be faithful.\n\nThe Church celebrates Saint Vincent of Saragossa on January 22. He became a saint because he stayed strong in faith, trusted God through suffering, and showed that love for Jesus is greater than fear.",
  bibleVerse: "Romans 8:18\nFor I reckon that the sufferings of this time are not worthy to be compared with the glory to come.",
  meaning: "This verse teaches that hard moments do not last forever. God promises joy and peace to those who trust Him and stay faithful.",
  prayer: "Dear God, thank You for Saint Vincent of Saragossa, who trusted You in difficult times. Please help me be brave, stay faithful, and trust You when things are hard. Amen.",
  action: "When something is difficult today, say a short prayer and remember that God is always with you."
},
"01-23": {
  title: "January 23  Saint Marianne Cope",
  story: "Saint Marianne Cope was born in Germany and later moved with her family to the United States. From a young age, she wanted to help people who were sick and suffering. She became a religious sister and worked as a nurse, caring for those who needed love and attention.\n\nSaint Marianne heard about very sick people living far away in Hawaii who were often avoided because of their illness. Even though many were afraid to go there, Marianne trusted God and volunteered to help. She cared for the sick with kindness, touched them without fear, and treated them with respect and love. She spent her life serving others and never turned anyone away.\n\nThe Church celebrates Saint Marianne Cope on January 23. She became a saint because of her great love, courage, and kindness. Her life teaches children that caring for others and showing love is one of the most beautiful ways to follow Jesus.",
  bibleVerse: "Matthew 25:36\nI was sick, and you visited me.",
  meaning: "This verse teaches that when we care for people who are sick or lonely, we are showing love to Jesus Himself.",
  prayer: "Dear Jesus, thank You for Saint Marianne Cope, who cared for the sick with love. Please help me be kind, gentle, and ready to help people who need care. Amen.",
  action: "Do one kind act today for someone who is sick, lonely, or needs help, and offer it to Jesus."
},
"01-24": {
  title: "January 24  Saint Francis de Sales",
  story: "Saint Francis de Sales was born in France and grew up in a loving family that valued learning and faith. From a young age, Francis loved God and wanted to serve Him, even though his family hoped he would become a lawyer. With patience and prayer, Francis followed God’s call and became a priest and later a bishop.\n\nSaint Francis lived during a time when many people had left the Catholic Church. Instead of arguing or being harsh, Francis taught with kindness, patience, and gentle words. He wrote letters and simple teachings to help people understand God’s love. Many people returned to the faith because Francis spoke with love and respect.\n\nThe Church celebrates Saint Francis de Sales on January 24. He became a saint because he showed that gentleness, patience, and love can bring people closer to God. His life teaches children that being kind and calm is a powerful way to follow Jesus.",
  bibleVerse: "Proverbs 15:1\nA mild answer breaketh wrath: but a harsh word stirreth up anger.",
  meaning: "This verse teaches that kind and gentle words can calm difficult situations. Speaking with love helps us act like Jesus.",
  prayer: "Dear God, thank You for Saint Francis de Sales, who taught others with kindness and patience. Please help me speak gently, be patient with others, and show love every day. Amen.",
  action: "Use gentle words today, especially when you feel upset, and try to make someone feel peaceful."
},
"01-25": {
  title: "January 25  The Conversion of Saint Paul",
  story: "Saint Paul was born in the city of Tarsus and was known as Saul when he was young. He was very educated and strongly believed he was doing the right thing, but he did not understand Jesus at first. Saul was unkind to Christians and tried to stop them from following Jesus.\n\nOne day, while Saul was traveling to the city of Damascus, a bright light from heaven suddenly surrounded him. Saul fell to the ground and heard Jesus speak to him, asking why he was hurting Him. Saul realized that he had been wrong. He became blind for a short time and needed help from others. After this, Saul changed completely. He was baptized, began to follow Jesus, and became known as Paul.\n\nThe Church celebrates the Conversion of Saint Paul on January 25. Paul became a great saint because he changed his heart, followed Jesus with love, and spent his life teaching others about God. His story teaches children that God can help anyone change and become good.",
  bibleVerse: "Acts 9:15\nThis man is to me a vessel of election, to carry my name before the Gentiles, and kings, and the children of Israel.",
  meaning: "This verse teaches that God can choose anyone for a good purpose. Even if we make mistakes, God can help us change and do great things.",
  prayer: "Dear Jesus, thank You for Saint Paul and for helping him change his heart. Please help me listen to You, say sorry when I am wrong, and choose to do what is right. Amen.",
  action: "If you made a mistake, say sorry today and try again with a kind and loving heart."
},
"01-26": {
  title: "January 26  Saints Timothy and Titus",
  story: "Saints Timothy and Titus were close friends and helpers of Saint Paul the Apostle. They learned to love Jesus by listening carefully to Paul’s teaching and watching how he lived his faith. Timothy helped care for Christians in the city of Ephesus, while Titus guided the Church on the island of Crete.\n\nBoth Timothy and Titus worked hard to teach others about Jesus, encourage believers, and help communities live in peace and love. They were young leaders, but they trusted God and did not give up, even when their work was difficult. Saint Paul wrote letters to them to guide and encourage them, reminding them to be brave, kind, and faithful.\n\nThe Church celebrates Saints Timothy and Titus on January 26. They became saints because they faithfully served God, helped the Church grow, and showed that learning from good teachers and helping others are beautiful ways to follow Jesus.",
  bibleVerse: "1 Timothy 4:12\nLet no man despise thy youth; but be thou an example of the faithful, in word, in conversation, in charity, in faith, in chastity.",
  meaning: "This verse teaches that they can do good and follow Jesus even when they are young. God loves it when children set a good example through kindness and faith.",
  prayer: "Dear God, thank You for Saints Timothy and Titus, who served You faithfully. Please help me listen to good teachers, grow in faith, and be kind and helpful to others. Amen.",
  action: "Be a good example today by showing kindness, obedience, or helping someone without being asked."
},
"01-27": {
  title: "January 27  Saint Angela Merici",
  story: "Saint Angela Merici was born in Italy and loved God from a very young age. She cared deeply for children, especially girls who did not have the chance to learn or grow safely. Angela believed that education and love could help children live good and holy lives.\n\nAs she grew older, Angela gathered other women who wanted to help children learn about God and live with kindness. Together, they began teaching, guiding, and protecting young girls. Angela trusted God completely and taught others to live with patience, prayer, and courage. She did not seek praise but quietly served wherever help was needed.\n\nThe Church celebrates Saint Angela Merici on January 27. She became a saint because of her great love for children, her trust in God, and her dedication to teaching and caring for others.",
  bibleVerse: "Proverbs 22:6\nTrain up a child in the way he should go: and when he is old, he will not depart from it.",
  meaning: "This verse teaches that learning good values when we are young helps us grow into kind and faithful adults. God is happy when children are taught with love and care.",
  prayer: "Dear God, thank You for Saint Angela Merici, who loved and taught children with care. Please help me learn good things, grow in kindness, and trust You every day. Amen.",
  action: "Listen carefully to your teacher or parent today and try your best to learn and help others."
},
"01-28": {
  title: "January 28  Saint Thomas Aquinas",
  story: "Saint Thomas Aquinas was born in Italy into a noble family. From a young age, Thomas loved learning and wanted to understand God better. Even though his family hoped he would become rich and powerful, Thomas chose to serve God and became a priest.\n\nThomas studied very hard and used his intelligence to explain the Catholic faith clearly. He wrote many books to help people understand God, faith, and truth. Even though he was very smart, Thomas was humble and prayed often. He believed that all wisdom comes from God and that learning should lead us to love God more.\n\nThe Church celebrates Saint Thomas Aquinas on January 28. He became a saint because he used his great intelligence to serve God, taught the faith with clarity and humility, and showed that loving God with our mind is also a beautiful way to follow Jesus.",
  bibleVerse: "Proverbs 2:6\nFor the Lord giveth wisdom: and out of his mouth cometh knowledge and understanding.",
  meaning: "This verse teaches that God is the source of all wisdom. When we learn and ask questions with a good heart, God helps us understand what is right.",
  prayer: "Dear God, thank You for Saint Thomas Aquinas, who loved learning and used it to serve You. Please help me enjoy learning, ask good questions, and use my knowledge to do good. Amen.",
  action: "Do your schoolwork or learning today with care and offer it to God as a way of loving Him."
},
"01-29": {
  title: "January 29  Saint Gildas the Wise",
  story: "Saint Gildas lived many years ago in the land of Britain. From a young age, he loved learning, prayer, and God’s truth. Gildas became a monk and teacher because he wanted to help people live good and holy lives.\n\nSaint Gildas traveled to different places, teaching others about Jesus and reminding them to choose kindness, honesty, and peace. He was called “the Wise” because he spoke truth gently and helped people understand right and wrong. Gildas believed that loving God also meant helping others grow better each day.\n\nThe Church celebrates Saint Gildas on January 29. He became a saint because he loved God’s truth, taught others with wisdom, and used his knowledge to guide people toward goodness.",
  bibleVerse: "Proverbs 9:10\nThe fear of the Lord is the beginning of wisdom.",
  meaning: "This verse teaches that true wisdom begins with loving and respecting God. When we listen to God and choose what is right, we grow wiser.",
  prayer: "Dear God, thank You for Saint Gildas the Wise, who loved truth and helped others learn. Please help me listen to You, grow in wisdom, and choose what is good. Amen.",
  action: "Before making a choice today, pause and ask God to help you choose what is right."
},
"01-30": {
  title: "January 30  Saint Martina of Rome",
  story: "Saint Martina lived in Rome during the early days of the Church. She loved Jesus deeply and chose to dedicate her life to Him. Martina was known for her strong faith and her courage, even when it was dangerous to be a Christian.\n\nWhen Martina refused to worship false gods, she was arrested because she would not give up her faith in Jesus. Saint Martina remained calm and prayerful, trusting God with her whole heart. According to Church tradition, Martina was killed with a sword because she chose to stay faithful to Jesus.\n\nThe Church celebrates Saint Martina on January 30. She became a saint because of her brave faith, her love for Jesus, and her willingness to give her life rather than deny Him.",
  bibleVerse: "Romans 8:38\nFor I am sure that neither death, nor life, nor angels, nor principalities, nor powers, shall be able to separate us from the love of God.",
  meaning: "This verse teaches that God’s love never leaves us. Nothing can separate us from God when we trust Him and stay close to Him.",
  prayer: "Dear God, thank You for Saint Martina, who trusted You completely. Please help me love You, stay faithful, and be brave when it is hard to do what is right. Amen.",
  action: "When something feels difficult today, say a short prayer and remember that God is always with you."
},
"01-31": {
  title: "January 31  Saint John Bosco",
  story: "Saint John Bosco was born in Italy into a poor family. When he was very young, his father died, and his mother worked hard to raise him with faith, honesty, and kindness. From childhood, John loved God and cared deeply for other children, especially those who were poor or had no one to guide them.\n\nAs a priest, John Bosco spent his life helping children who lived on the streets or had no chance to learn. He welcomed them with joy, taught them about Jesus, helped them study, and showed them how to live good lives. John believed that children learn best when they are loved, encouraged, and treated with respect.\n\nThe Church celebrates Saint John Bosco on January 31. He became a saint because of his great love for children, his joyful spirit, and his trust in God. His life teaches children that kindness, joy, and helping others are beautiful ways to follow Jesus.",
  bibleVerse: "Matthew 19:14\nSuffer the little children, and forbid them not to come to me: for the kingdom of heaven is for such.",
  meaning: "This verse teaches that Jesus loves them very much and wants them close to Him. God is happy when children learn, pray, and grow in love.",
  prayer: "Dear Jesus, thank You for Saint John Bosco, who loved and cared for children. Please help me be joyful, kind, and loving to everyone, especially those who need help. Amen.",
  action: "Show kindness today by helping a younger child or encouraging a friend with loving words."
},
"02-01": {
  title: "February 1  Saint Brigid of Kildare",
  story: "Saint Brigid lived in Ireland and loved God from a very young age. She was known for her great kindness and generosity, especially toward the poor and those in need. Brigid often shared food, clothing, and help with anyone who asked, trusting that God would provide for everyone.\n\nAs she grew older, Saint Brigid dedicated her life to God and helped establish a community where prayer, learning, and care for the poor were very important. Many people admired her gentle heart and her desire to serve others quietly. She showed that loving God is lived out through simple acts of kindness and generosity.\n\nThe Church celebrates Saint Brigid on February 1 because of her deep faith, her generosity, and her loving care for everyone she met.",
  bibleVerse: "Matthew 25:35\nFor I was hungry, and you gave me to eat; I was thirsty, and you gave me to drink.",
  meaning: "Helping those who are hungry, thirsty, or in need is a way of serving Jesus Himself. Acts of kindness and generosity are precious in God’s sight.",
  prayer: "Dear God, thank You for Saint Brigid, who lived with a generous and loving heart. Help me to care for others and to share what I have with kindness. Amen.",
  action: "Do one kind act today, such as sharing food, helping at home, or being kind to someone who feels left out."
},
};

// Add placeholder entries for all days of the year
function generatePlaceholders() {
    const days = [
        // January
        ...Array.from({ length: 31 }, (_, i) => `01-${String(i + 1).padStart(2, '0')}`),
        // February
        ...Array.from({ length: 28 }, (_, i) => `02-${String(i + 1).padStart(2, '0')}`),
        // March
        ...Array.from({ length: 31 }, (_, i) => `03-${String(i + 1).padStart(2, '0')}`),
        // April
        ...Array.from({ length: 30 }, (_, i) => `04-${String(i + 1).padStart(2, '0')}`),
        // May
        ...Array.from({ length: 31 }, (_, i) => `05-${String(i + 1).padStart(2, '0')}`),
        // June
        ...Array.from({ length: 30 }, (_, i) => `06-${String(i + 1).padStart(2, '0')}`),
        // July
        ...Array.from({ length: 31 }, (_, i) => `07-${String(i + 1).padStart(2, '0')}`),
        // August
        ...Array.from({ length: 31 }, (_, i) => `08-${String(i + 1).padStart(2, '0')}`),
        // September
        ...Array.from({ length: 30 }, (_, i) => `09-${String(i + 1).padStart(2, '0')}`),
        // October
        ...Array.from({ length: 31 }, (_, i) => `10-${String(i + 1).padStart(2, '0')}`),
        // November
        ...Array.from({ length: 30 }, (_, i) => `11-${String(i + 1).padStart(2, '0')}`),
        // December
        ...Array.from({ length: 31 }, (_, i) => `12-${String(i + 1).padStart(2, '0')}`)
    ];

    const monthNames = [
        "January", "February", "March", "April", "May", "June",
        "July", "August", "September", "October", "November", "December"
    ];

    days.forEach(key => {
        if (!DAILY_CONTENT[key]) {
            const [month, day] = key.split("-");
            const monthName = monthNames[parseInt(month, 10) - 1];

            DAILY_CONTENT[key] = {
                title: `${monthName} ${parseInt(day, 10)}  (Saint / Feast to be added)`,
                story: "(Story content needed — add verified Catholic facts here)",
                bibleVerse: "(Bible verse reference and text — Douay-Rheims)",
                meaning: "(Simple child-friendly meaning of the Bible verse)",
                prayer: "(Short prayer written for children)",
                action: "(One simple action a child can do today)"
            };
        }
    });
}

// Generate all placeholders on load
generatePlaceholders();
